// The full product-tour timeline — the single source of truth for pacing.
//
// Every narrated scene is sized from its voice-over clip (src/vo-meta.ts, which
// is regenerated by scripts/make-voice.mjs), so the visuals can never drift out
// of sync with the audio. Chapter cards and the bookends use fixed lengths.
// Scenes overlap by TRANSITION frames (TransitionSeries in Promo.tsx).
import { COLORS } from './theme';
import { VO_FRAMES } from './vo-meta';
import type { Token } from './components/KineticText';

export const TRANSITION = 16; // overlap between adjacent scenes

const LEAD_IN = 12; // frames before the VO starts inside a scene
const TAIL = 22; // hold after the VO ends
const CHAPTER = 60; // act-divider card length
const MIN_TOUR = 140; // floor so short lines still breathe
const HOOK_TAIL = 38; // brand hold
const CTA_TAIL = 180; // long hold so the install commands + links stay readable

// Per-act accent colours give each chapter its own identity.
const A = {
  brand: COLORS.coral,
  mc: COLORS.coral,
  crew: COLORS.amber,
  plan: COLORS.blue,
  run: COLORS.green,
  collab: COLORS.coralBright,
  learn: COLORS.gold,
} as const;

export type TransKind =
  | { type: 'fade' }
  | { type: 'slide'; dir: 'from-left' | 'from-right' | 'from-top' | 'from-bottom' }
  | null;

type Raw =
  | { kind: 'hook'; vo: number }
  | { kind: 'problem'; vo: number }
  | { kind: 'cta'; vo: number }
  | { kind: 'build'; vo: number } // animated complete-run kanban centrepiece
  | { kind: 'chapter'; index: string; title: Token[]; accent: string }
  | {
      kind: 'design'; // cross-fade two screenshots (device switch / redesign)
      vo: number;
      srcA: string;
      srcB: string;
      labelA: string;
      labelB: string;
      eyebrow: string;
      title: Token[];
      browserTitle: string;
      accent: string;
      portrait?: boolean;
    }
  | {
      kind: 'tour';
      vo: number;
      screenshot: string;
      browserTitle: string;
      eyebrow: string;
      title: Token[];
      chips: string[];
      accent: string;
      portrait?: boolean;
    };

export type Scene = Raw & {
  id: string;
  start: number;
  dur: number;
  trans: TransKind; // transition that FOLLOWS this scene
  voSrc?: string;
  voFrom?: number;
  voDur?: number;
};

