function durOf(r: Raw): number {
  switch (r.kind) {
    case 'chapter':
      return CHAPTER;
    case 'hook':
      return LEAD_IN + VO_FRAMES[r.vo] + HOOK_TAIL;
    case 'cta':
      return LEAD_IN + VO_FRAMES[r.vo] + CTA_TAIL;
    case 'problem':
      return LEAD_IN + VO_FRAMES[r.vo] + TAIL;
    case 'tour':
    case 'build':
    case 'design':
      return Math.max(MIN_TOUR, LEAD_IN + VO_FRAMES[r.vo] + TAIL);
  }
}

// A clean forward slide between content beats; gentle fades around chapter cards.
function transBetween(cur: Raw, nxt: Raw): TransKind {
  if (cur.kind === 'chapter' || nxt.kind === 'chapter') return { type: 'fade' };
  return { type: 'slide', dir: 'from-right' };
}

function build(): Scene[] {
  const out: Scene[] = [];
  let cursor = 0;
  RAW.forEach((r, i) => {
    const dur = durOf(r);
    const start = cursor;
    const trans: TransKind = i < RAW.length - 1 ? transBetween(r, RAW[i + 1]) : null;
    const scene: Scene = { ...r, id: `${i}-${r.kind}`, start, dur, trans };
    if ('vo' in r) {
      scene.voSrc = `audio/vo/vo-${r.vo + 1}.wav`;
      scene.voFrom = start + LEAD_IN;
      scene.voDur = VO_FRAMES[r.vo];
    }
    out.push(scene);
    // next scene begins TRANSITION frames before this one ends (overlap).
    cursor = start + dur - (i < RAW.length - 1 ? TRANSITION : 0);
  });
  return out;
}

export const SCENES: Scene[] = build();

export const TOTAL_FRAMES =
  RAW.reduce((sum, r) => sum + durOf(r), 0) - (RAW.length - 1) * TRANSITION;

// Background score. null = silent. The bundled wisp-theme.wav is the synthesised,
// license-free bed from scripts/make-music.mjs (regenerated to TOTAL_FRAMES).
export const MUSIC_SRC: string | null = 'audio/wisp-theme.wav';
